def average_goals(goals):
    if not goals:
        return 0.00
    total_goals = sum(goals)
    num_matches = len(goals)
    average = total_goals / num_matches
    return round(average, 2)

def calculate_total_cost(dishes, ingredient_costs):
    total_cost = 0.0
    for dish in dishes:
        for ingredient, quantity in dish.items():
            total_cost += quantity * ingredient_costs[ingredient]
    return total_cost

def lowest_common_ancestor(a: int, b: int) -> int:
    while a != b:
        if a > b:
            a //= 2
        else:
            b //= 2
    return a
